104	
105	  let totalReimbursement = 0;
106	  for (const claim of claimEntries) {
107	    const item = policyItems[claim.itemIndex];
108	    if (item.dragonMaterial) {
109	      totalReimbursement += claim.damageAmount;
110	    } else if (item.enchantment && item.enchantment >= 8) {
111	      totalReimbursement += claim.damageAmount * 0.5;
112	    }
113	  }
114	
115	  return totalReimbursement;
116	}
